                if (!exists) {
                    myWorkList.push(doc);
                }
            }
        });

        setDocs(myWorkList);

    } catch (error) {
        console.error("Error loading work list:", error);
    } finally {
        setLoading(false);
    }
  };

  // --- DERIVED FILTER OPTIONS ---
  const availableProjects = useMemo(() => Array.from(new Set(docs.map(d => d.project).filter(Boolean))).sort(), [docs]);
  const availableMacros = useMemo(() => {
    let list = docs;
    if (filterProject) list = list.filter(d => d.project === filterProject);
    return Array.from(new Set(list.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [docs, filterProject]);

  const availableProcesses = useMemo(() => {
    let list = docs;
    if (filterProject) list = list.filter(d => d.project === filterProject);
    if (filterMacro) list = list.filter(d => d.macroprocess === filterMacro);
    return Array.from(new Set(list.map(d => d.process).filter(Boolean))).sort();
  }, [docs, filterProject, filterMacro]);

  const handleSort = (key: SortOption) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const clearFilters = () => {
    setFilterProject('');
    setFilterMacro('');
    setFilterProcess('');
    setFilterState('');
    setSearchTerm('');
  };

  // --- FILTER & SORT LOGIC ---
  const processedDocs = useMemo(() => {
      let filtered = [...docs];

      if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
      if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
      if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
      if (filterState) filtered = filtered.filter(d => d.state === filterState);

      if (searchTerm) {
          const lowerTerm = searchTerm.toLowerCase();
          filtered = filtered.filter(d => 
              (d.project || '').toLowerCase().includes(lowerTerm) ||
              (d.microprocess || '').toLowerCase().includes(lowerTerm) ||
              (d.title || '').toLowerCase().includes(lowerTerm)
          );
      }

      return filtered.sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return ((STATE_CONFIG[a.state]?.progress || 0) - (STATE_CONFIG[b.state]?.progress || 0)) * modifier;
              case 'updatedAt': return (new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime()) * modifier;
              default: return 0;
          }
      });
  }, [docs, filterProject, filterMacro, filterProcess, filterState, searchTerm, sortConfig]);

  const hasActiveFilters = filterProject || filterMacro || filterProcess || filterState || searchTerm;

  const SortIcon = ({ column }: { column: SortOption }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 ml-1 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600 ml-1" /> : <ArrowDown size={14} className="text-indigo-600 ml-1" />;
  };

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Activity className="animate-spin mb-2" />Cargando lista de trabajo...</div>;

  return (
    <div className="space-y-6 pb-12 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <ListTodo className="text-indigo-600" />
                Lista de Trabajo
            </h1>
            <p className="text-slate-500 text-sm">
                {user.role === UserRole.ANALYST ? 'Mis asignaciones pendientes.' : 'Revisiones y asignaciones pendientes.'}
            </p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm uppercase tracking-wider">
                        <Filter size={16} className="text-indigo-600" />
                        Filtros de Búsqueda
                    </h2>
                    {hasActiveFilters && (
                        <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 font-bold flex items-center gap-1 transition-colors">
                            <X size={14} /> Limpiar Filtros
                        </button>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-3">
                    {/* Filtro Proyecto */}
                    <div className="relative">
                        <FolderTree size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => { setFilterProject(e.target.value); setFilterMacro(''); setFilterProcess(''); }}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white cursor-pointer"
                        >
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>

                    {/* Filtro Macroproceso */}
                    <div className="relative">
                        <Layers size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterMacro} 
                            onChange={(e) => { setFilterMacro(e.target.value); setFilterProcess(''); }}
                            disabled={!filterProject && availableMacros.length === 0}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white disabled:bg-slate-100 cursor-pointer"
                        >
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                    </div>

                    {/* Filtro Proceso */}
                    <div className="relative">
                        <Network size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterProcess} 
                            onChange={(e) => setFilterProcess(e.target.value)}
                            disabled={!filterMacro && availableProcesses.length === 0}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white disabled:bg-slate-100 cursor-pointer"
                        >
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>

                    {/* Filtro Estado */}
                    <div className="relative">
                        <Activity size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterState} 
                            onChange={(e) => setFilterState(e.target.value)}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white cursor-pointer"
                        >
                            <option value="">ESTADO</option>
                            {Object.keys(STATE_CONFIG).filter(k => k !== DocState.APPROVED).map(key => (
                                <option key={key} value={key}>{STATE_CONFIG[key as DocState].label.split('(')[0]}</option>
                            ))}
                        </select>
                    </div>

                    {/* Buscador de texto */}
                    <div className="relative">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="BUSCAR..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-8 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                        {searchTerm && (
                            <button onClick={() => setSearchTerm('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"><X size={14} /></button>
                        )}
                    </div>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-black tracking-widest bg-slate-50 border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-4">Jerarquía Organizacional</th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('microprocess')}>Microproceso <SortIcon column="microprocess" /></th>
                            <th className="px-4 py-4">Documento / Tipo</th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('state')}>Estado Actual <SortIcon column="state" /></th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('updatedAt')}>Última Actividad <SortIcon column="updatedAt" /></th>
                            <th className="px-4 py-4 text-right">Gestión</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {processedDocs.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="p-20 text-center text-slate-400">
                                    <div className="flex flex-col items-center">
                                        <Search size={40} className="mb-2 opacity-20" />
                                        <p className="font-bold">No se encontraron tareas pendientes.</p>
                                        <p className="text-xs mt-1 text-slate-400">Ajuste sus filtros o verifique su bandeja de entrada.</p>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            processedDocs.map((doc, idx) => (
                                <tr key={`${doc.id}-${idx}`} className={`group hover:bg-slate-50/50 transition-colors ${doc.hasPendingRequest ? 'bg-indigo-50/30' : ''}`}>
                                    <td className="px-4 py-4">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="text-[9px] font-black bg-slate-800 text-white px-1.5 py-0.5 rounded tracking-tighter uppercase">{doc.project}</span>
                                            <span className="text-[9px] font-bold text-slate-400 uppercase truncate max-w-[120px]">{doc.macroprocess}</span>
                                        </div>
                                        <div className="text-[10px] text-slate-500 pl-1 border-l border-slate-200 truncate max-w-[180px]">{doc.process}</div>
                                    </td>
                                    <td className="px-4 py-4 font-black text-slate-800 uppercase tracking-tight">
                                        {doc.microprocess || 'General'}
                                    </td>
                                    <td className="px-4 py-4">
                                        <div className="flex items-center gap-2">
                                            <FileText size={16} className="text-indigo-400 shrink-0" />
                                            <div className="min-w-0">
                                                {doc.docType ? (
                                                    <span className="text-[10px] font-black px-1.5 py-0.5 rounded border bg-indigo-50 text-indigo-700 border-indigo-200">
                                                        {doc.docType}
                                                    </span>
                                                ) : <span className="text-xs text-slate-600 truncate block">{doc.title}</span>}
                                                {doc.hasPendingRequest && (
                                                    <div className="flex items-center text-[8px] text-red-600 font-black uppercase mt-1 animate-pulse" title="Requiere Atención">
                                                        <AlertTriangle size={10} className="mr-1"/> Acción Pendiente
                                                    </div>
                                                )}
                                            </div>
                                        </div>
                                    </td>
                                    <td className="px-4 py-4">
                                        <div className={`inline-flex px-2 py-1 rounded-lg text-[10px] font-black uppercase tracking-tighter border shadow-sm ${STATE_CONFIG[doc.state].color}`}>
                                            {STATE_CONFIG[doc.state].label.split('(')[0]}
                                        </div>
                                        <div className="text-[9px] font-mono text-slate-400 mt-1 flex items-center gap-1">
                                            <span>v{doc.version}</span>
                                            <span className="text-slate-200">•</span>
                                            <span>{doc.progress}%</span>
                                        </div>
                                    </td>
                                    <td className="px-4 py-4">
                                        <div className="flex items-center gap-1.5 text-slate-500 font-bold text-[10px]">
                                            <Calendar size={12} className="text-slate-300" />
                                            <span>{doc.state === DocState.NOT_STARTED ? '-' : new Date(doc.updatedAt).toLocaleDateString()}</span>
                                        </div>
                                    </td>
                                    <td className="px-4 py-4 text-right">
                                        <Link 
                                            to={`/doc/${doc.id}`} 
                                            state={{ docData: doc }}
                                            className="inline-flex items-center gap-2 px-3 py-1.5 bg-white border border-slate-200 text-indigo-600 hover:bg-indigo-600 hover:text-white hover:border-indigo-600 rounded-lg text-[10px] font-black uppercase tracking-widest transition-all shadow-sm active:scale-95"
                                        >
                                            Ver Detalle <ArrowRight size={12} />
                                        </Link>
                                    </td>
                                </tr>
                            ))
                        )}
                    </tbody>
                </table>
            </div>

            <div className="p-4 bg-slate-50/30 border-t border-slate-100 flex flex-col md:flex-row justify-between items-center gap-4">
                <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest">
                    Mostrando <b>{processedDocs.length}</b> registros de un universo de <b>{docs.length}</b> asignaciones pendientes.
                </div>
                <div className="flex items-center gap-4">
                    <div className="flex items-center gap-1.5">
                        <div className="w-2 h-2 rounded-full bg-indigo-500 shadow-sm shadow-indigo-200"></div>
                        <span className="text-[9px] font-black text-slate-400 uppercase">Tarea en curso</span>
                    </div>
                    <div className="flex items-center gap-1.5">
                        <div className="w-2 h-2 rounded-full bg-red-500 animate-pulse"></div>
                        <span className="text-[9px] font-black text-slate-400 uppercase">Solicitud de revisión</span>
                    </div>
                </div>
            </div>
      </div>
    </div>
  );
};

export default WorkList;

import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
import { Menu, X, FileText, BarChart2, PlusCircle, LogOut, User as UserIcon, Users, ClipboardList, Inbox, Database, Settings, ListTodo, Network, PieChart, UserCheck, BookOpen, CalendarRange, History } from 'lucide-react';
import { User, UserRole, DocState, Document } from '../types';
import { NotificationService } from '../services/firebaseBackend';

interface LayoutProps {
  children: React.ReactNode;
  user: User;
  onLogout: () => void;
}

const Layout: React.FC<LayoutProps> = ({ children, user, onLogout }) => {
  const [isSidebarOpen, setIsSidebarOpen] = useState(false);
  const [inboxCount, setInboxCount] = useState(0);
  const location = useLocation();

  const isActive = (path: string) => location.pathname === path ? 'bg-slate-800 text-white shadow-inner' : 'text-slate-300 hover:bg-slate-800 hover:text-white';

  useEffect(() => {
    if (!user?.id) return;

    // Establishing reliable real-time connection for notification badge
    const unsubscribeBadge = NotificationService.subscribeToUnreadCount(user.id, (count) => {
        setInboxCount(count);
    });

    return () => {
        if (unsubscribeBadge) unsubscribeBadge();
    };
  }, [user?.id]); 

  const NavItem = ({ to, icon: Icon, label, badge }: { to: string, icon: any, label: string, badge?: number }) => (
    <Link
      to={to}
      onClick={() => setIsSidebarOpen(false)}
      className={`flex items-center space-x-3 px-4 py-3 rounded-lg transition-all duration-200 group ${isActive(to)}`}
    >
      <div className="relative">
        <Icon 
            size={20} 
            className={isActive(to).includes('bg-slate-800') ? 'text-indigo-400' : 'text-slate-400 group-hover:text-white'} 
        />
        {badge !== undefined && badge > 0 && (
            <span className="absolute -top-2.5 -right-2.5 flex h-5 w-5 items-center justify-center rounded-full bg-red-600 text-[10px] font-black text-white shadow-md ring-2 ring-slate-900 animate-pulse px-1">
                {badge > 99 ? '99+' : badge}
            </span>
        )}
      </div>
      <span className="font-medium flex-1">{label}</span>
    </Link>
  );

  const isGuest = user.role === UserRole.GUEST;
  const isAdminOrCoord = user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR;

  const canAccessReports = isAdminOrCoord || ((user.role === UserRole.ANALYST || isGuest) && user.canAccessReports);
  const canAccessReferents = isAdminOrCoord || (user.role === UserRole.ANALYST && user.canAccessReferents);
  const canAccessGantt = isAdminOrCoord || ((user.role === UserRole.ANALYST || isGuest) && user.canAccessGantt);

  return (
    <div className="flex h-screen bg-slate-50 overflow-hidden">
      {isSidebarOpen && (
        <div className="fixed inset-0 bg-black/60 z-20 md:hidden backdrop-blur-sm transition-opacity" onClick={() => setIsSidebarOpen(false)} />
      )}
      <aside className={`fixed inset-y-0 left-0 z-30 w-64 bg-slate-900 text-white transform transition-transform duration-300 ease-in-out md:translate-x-0 md:static md:flex-shrink-0 ${isSidebarOpen ? 'translate-x-0' : '-translate-x-full'}`}>
        <div className="h-full flex flex-col">
          <div className="p-6 border-b border-slate-800 flex justify-between items-center flex-shrink-0 bg-slate-950/30">
            <div>
                <h1 className="text-xl font-bold tracking-tight text-white">SGD</h1>
                <p className="text-[10px] text-indigo-400 font-bold uppercase tracking-widest">{isGuest ? 'Visor Institucional' : 'Gestión Documental'}</p>
            </div>
            <button onClick={() => setIsSidebarOpen(false)} className="md:hidden text-slate-400 hover:text-white">
                <X size={24} />
            </button>
          </div>
          <nav className="flex-1 px-4 py-6 space-y-1.5 overflow-y-auto">
            {!isGuest && (
              <>
                <div className="pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Operación Diaria</div>
                <NavItem to="/inbox" icon={Inbox} label="Bandeja de Entrada" badge={inboxCount} />
                <NavItem to="/worklist" icon={ListTodo} label="Lista de Trabajo" />
                <NavItem to="/new" icon={PlusCircle} label="Nueva Solicitud" />
              </>
            )}

            <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Visualización y Análisis</div>
            <NavItem to="/" icon={BarChart2} label="Dashboard" />

            {(canAccessReports || canAccessReferents || canAccessGantt || isAdminOrCoord) && (
              <>
                {canAccessReports && <NavItem to="/admin/reports" icon={PieChart} label="Reportes" />}
                {canAccessGantt && <NavItem to="/admin/gantt" icon={CalendarRange} label="Diagrama Gantt" />}
                {user.role === UserRole.ADMIN && <NavItem to="/admin/events" icon={History} label="Log de Eventos" />}
                {isAdminOrCoord && (
                    <>
                        <NavItem to="/admin/structure" icon={Network} label="Estructura" />
                        <NavItem to="/admin/assignments" icon={ClipboardList} label="Asignaciones" />
                    </>
                )}
                {canAccessReferents && <NavItem to="/admin/referents" icon={UserCheck} label="Referentes" />}
                {user.role === UserRole.ADMIN && (
                    <>
                        <NavItem to="/admin/database" icon={Database} label="Base de Datos" />
                        <NavItem to="/admin/users" icon={Users} label="Usuarios" />
                    </>
                )}
              </>
            )}
            <div className="pt-6 pb-2 text-[10px] font-bold text-slate-500 uppercase tracking-widest px-4">Mi Cuenta</div>
            {!isGuest && <NavItem to="/manual" icon={BookOpen} label="Manual de Usuario" />}
            <NavItem to="/profile" icon={Settings} label="Mi Perfil" />
          </nav>
          <div className="p-4 border-t border-slate-800 flex-shrink-0 bg-slate-950/20">
            <button onClick={onLogout} className="w-full flex items-center justify-center space-x-2 bg-slate-800 hover:bg-red-900/40 hover:text-red-200 p-2.5 rounded-lg transition-all text-sm font-semibold border border-transparent hover:border-red-800/50">
                <LogOut size={16} />
                <span>Cerrar Sesión</span>
            </button>
          </div>
        </div>
      </aside>
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="bg-white border-b border-gray-200 p-4 flex items-center justify-between md:hidden flex-shrink-0 shadow-sm">
            <button onClick={() => setIsSidebarOpen(true)} className="text-slate-600 hover:bg-slate-50 p-1 rounded-md"><Menu size={24} /></button>
            <div className="flex flex-col items-center">
              <span className="font-bold text-slate-900 text-sm">SGD Visor</span>
              <span className="text-[10px] text-indigo-600 font-bold uppercase tracking-tight">Acceso Lectura</span>
            </div>
            <div className="w-6" />
        </header>
        <main className="flex-1 overflow-y-auto p-4 md:p-8 bg-slate-50/50">{children}</main>
      </div>
    </div>
  );
};

export default Layout;

import React from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import Layout from './components/Layout';
import Login from './views/Login';
import Dashboard from './views/Dashboard';
import CreateDocument from './views/CreateDocument';
import DocumentDetail from './views/DocumentDetail';
import AdminUsers from './views/AdminUsers';
import AdminAssignments from './views/AdminAssignments';
import AdminHierarchy from './views/AdminHierarchy'; 
import AdminDatabase from './views/AdminDatabase';
import AdminReferents from './views/AdminReferents';
import AdminGantt from './views/AdminGantt';
import AdminEventLog from './views/AdminEventLog';
import Reports from './views/Reports'; 
import Buffer from './views/Buffer';
import WorkList from './views/WorkList';
import Profile from './views/Profile';
import ManualAnalista from './views/ManualAnalista';
import { UserRole } from './types'; 
import { logoutUser } from './services/firebaseAuthService'; 
import { useAuthStatus } from './hooks/useAuthStatus'; 
import { RefreshCw } from 'lucide-react';

const App: React.FC = () => {
    const { user, cargando } = useAuthStatus(); 

    const handleLogout = async () => {
        await logoutUser(); 
    };

    if (cargando) {
        return (
            <div className="flex flex-col h-screen items-center justify-center bg-slate-50 gap-4">
                <div className="flex items-center gap-2 text-indigo-600 font-semibold animate-pulse">
                    <RefreshCw className="animate-spin" />
                    Cargando aplicación...
                </div>
            </div>
        );
    }

    return (
        <HashRouter>
            <Routes>
                <Route path="/login" element={!user ? <Login /> : <Navigate to="/" />} />
                <Route
                    path="*"
                    element={
                        user ? (
                            <Layout user={user} onLogout={handleLogout}>
                                <Routes>
                                    {/* Página de entrada inteligente basada en perfil */}
                                    <Route 
                                        path="/" 
                                        element={user.role === UserRole.ANALYST ? <Navigate to="/worklist" replace /> : <Dashboard user={user} />} 
                                    />

                                    {/* Ruta explícita para el Dashboard */}
                                    <Route path="/dashboard" element={<Dashboard user={user} />} />

                                    <Route path="/inbox" element={<Buffer user={user} />} />
                                    <Route path="/worklist" element={<WorkList user={user} />} />
                                    <Route path="/new" element={<CreateDocument user={user} />} />
                                    <Route path="/doc/:id" element={<DocumentDetail user={user} />} />
                                    <Route path="/profile" element={<Profile user={user} onUpdate={() => window.location.reload()} />} /> 
                                    <Route path="/manual" element={<ManualAnalista />} />

                                    <Route 
                                        path="/admin/referents" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || (user.role === UserRole.ANALYST && user.canAccessReferents)) 
                                            ? <AdminReferents user={user} /> 
                                            : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/reports" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || ((user.role === UserRole.ANALYST || user.role === UserRole.GUEST) && user.canAccessReports)) 
                                            ? <Reports user={user} /> 
                                            : <Navigate to="/" />} 
                                    />
                                    <Route 
                                        path="/admin/gantt" 
                                        element={(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR || ((user.role === UserRole.ANALYST || user.role === UserRole.GUEST) && user.canAccessGantt)) 
                                            ? <AdminGantt user={user} /> 
                                            : <Navigate to="/" />} 
                                    />

                                    {(user.role === UserRole.ADMIN || user.role === UserRole.COORDINATOR) && (
                                      <>
                                        <Route path="/admin/structure" element={<AdminHierarchy user={user} />} />
                                        <Route path="/admin/assignments" element={<AdminAssignments user={user} />} />
                                      </>
                                    )}

                                    {user.role === UserRole.ADMIN && (
                                        <>
                                            <Route path="/admin/users" element={<AdminUsers />} />
                                            <Route path="/admin/database" element={<AdminDatabase />} />
                                            <Route path="/admin/events" element={<AdminEventLog user={user} />} />
                                        </>
                                    )}
                                    <Route path="*" element={<Navigate to="/" />} />
                                </Routes>
                            </Layout>
                        ) : (
                            <Navigate to="/login" />
                        )
                    }
                />
            </Routes>
        </HashRouter>
    );
};

export default App;

import React, { useState, useEffect } from 'react';
import { useLocation, Link, useNavigate } from 'react-router-dom';
