export default Layout;

import React, { useEffect, useState, useMemo } from 'react';
import { Link } from 'react-router-dom';
import { DocumentService, HierarchyService } from '../services/firebaseBackend';
import { Document, User, DocState, UserRole, DocType } from '../types';
import { STATE_CONFIG } from '../constants';
import { Filter, ArrowRight, Calendar, ListTodo, Activity, FileText, Search, ArrowUp, ArrowDown, ArrowUpDown, X, AlertTriangle, FolderTree, Layers, Network } from 'lucide-react';

interface Props {
  user: User;
}

type SortOption = 'microprocess' | 'state' | 'updatedAt';

const WorkList: React.FC<Props> = ({ user }) => {
  const [docs, setDocs] = useState<Document[]>([]);
  const [loading, setLoading] = useState(true);

  // Filters & Search State
  const [filterProject, setFilterProject] = useState('');
  const [filterMacro, setFilterMacro] = useState('');
  const [filterProcess, setFilterProcess] = useState('');
  const [filterState, setFilterState] = useState('');
  const [searchTerm, setSearchTerm] = useState('');

  // Sorting State
  const [sortConfig, setSortConfig] = useState<{ key: SortOption; direction: 'asc' | 'desc' }>({
    key: 'updatedAt',
    direction: 'desc'
  });

  useEffect(() => {
    loadData();
  }, []);

  const normalize = (str: string | undefined) => {
      if (!str) return '';
      return str.trim().toUpperCase().normalize("NFD").replace(/[\u0300-\u036f]/g, "");
  };

  const loadData = async () => {
    setLoading(true);
    try {
        const [realDocsData, hierarchy] = await Promise.all([
            DocumentService.getAll(),
            HierarchyService.getFullHierarchy()
        ]);

        // 1. Map Real Docs for lookup
        const realDocMap = new Map<string, Document>();
        realDocsData.forEach(doc => {
            if (doc.project && (doc.microprocess || doc.title)) {
                const microName = doc.microprocess || doc.title.split(' - ')[0] || doc.title;
                const docType = doc.docType || 'AS IS';
                const key = `${normalize(doc.project)}|${normalize(microName)}|${normalize(docType)}`;

                // Use latest
                const existing = realDocMap.get(key);
                if (!existing || new Date(doc.updatedAt).getTime() > new Date(existing.updatedAt).getTime()) {
                    realDocMap.set(key, { ...doc, microprocess: microName, docType: docType as DocType });
                }
            }
        });

        // 2. Build Work List from Hierarchy (Assignments)
        const myWorkList: Document[] = [];
        const hierarchyKeys = Object.keys(hierarchy);

        const isCoordOrAdmin = user.role === UserRole.COORDINATOR || user.role === UserRole.ADMIN;
        const reviewStates = [
            DocState.INTERNAL_REVIEW, 
            DocState.SENT_TO_REFERENT, 
            DocState.REFERENT_REVIEW, 
            DocState.SENT_TO_CONTROL, 
            DocState.CONTROL_REVIEW
        ];

        hierarchyKeys.forEach(proj => {
            Object.keys(hierarchy[proj]).forEach(macro => {
                Object.keys(hierarchy[proj][macro]).forEach(proc => {
                    const nodes = hierarchy[proj][macro][proc];
                    nodes.forEach(node => {
                        if (node.active === false) return; 

                        const requiredTypes = (node.requiredTypes && node.requiredTypes.length > 0) 
                            ? node.requiredTypes 
                            : ['AS IS', 'FCE', 'PM', 'TO BE'];

                        requiredTypes.forEach(type => {
                            const key = `${normalize(proj)}|${normalize(node.name)}|${normalize(type)}`;

                            if (realDocMap.has(key)) {
                                // Exists in DB
                                const realDoc = realDocMap.get(key)!;

                                // LOGIC: Show if assigned OR if it's pending review and I'm a coordinator
                                const isAssigned = node.assignees && node.assignees.includes(user.id);
                                const isPendingReview = isCoordOrAdmin && reviewStates.includes(realDoc.state);

                                if ((isAssigned || isPendingReview) && realDoc.state !== DocState.APPROVED) {
                                    myWorkList.push({
                                        ...realDoc,
                                        macroprocess: macro,
                                        process: proc,
                                        project: proj,
                                        assignees: node.assignees
                                    });
                                }
                            } else {
                                // Virtual (Not Started)
                                // Only show not started if explicitly assigned
                                const isAssigned = node.assignees && node.assignees.includes(user.id);
                                if (isAssigned) {
                                    myWorkList.push({
                                        id: `virtual-${key}-${Date.now()}`,
                                        title: `${node.name} - ${type}`,
                                        description: 'Pendiente de inicio',
                                        project: proj,
                                        macroprocess: macro,
                                        process: proc,
                                        microprocess: node.name,
                                        docType: type as DocType,
                                        authorId: '',
                                        authorName: '',
                                        assignedTo: user.id,
                                        assignees: node.assignees,
                                        state: DocState.NOT_STARTED,
                                        version: '-',
                                        progress: 0,
                                        files: [],
                                        createdAt: new Date().toISOString(),
                                        updatedAt: new Date(0).toISOString(), 
                                        hasPendingRequest: false
                                    });
                                }
                            }
                        });
                    });
                });
            });
        });

        // 3. Add any "Real" documents that might be assigned but outside hierarchy (Orphans)
        realDocMap.forEach((doc) => {
            const isAssigned = doc.assignees && doc.assignees.includes(user.id);
            const isPendingReview = isCoordOrAdmin && reviewStates.includes(doc.state);

            if ((isAssigned || isPendingReview) && doc.state !== DocState.APPROVED) {
                const exists = myWorkList.some(d => d.id === doc.id);
                if (!exists) {
                    myWorkList.push(doc);
                }
            }
        });

        setDocs(myWorkList);

    } catch (error) {
        console.error("Error loading work list:", error);
    } finally {
        setLoading(false);
    }
  };

  // --- DERIVED FILTER OPTIONS ---
  const availableProjects = useMemo(() => Array.from(new Set(docs.map(d => d.project).filter(Boolean))).sort(), [docs]);
  const availableMacros = useMemo(() => {
    let list = docs;
    if (filterProject) list = list.filter(d => d.project === filterProject);
    return Array.from(new Set(list.map(d => d.macroprocess).filter(Boolean))).sort();
  }, [docs, filterProject]);

  const availableProcesses = useMemo(() => {
    let list = docs;
    if (filterProject) list = list.filter(d => d.project === filterProject);
    if (filterMacro) list = list.filter(d => d.macroprocess === filterMacro);
    return Array.from(new Set(list.map(d => d.process).filter(Boolean))).sort();
  }, [docs, filterProject, filterMacro]);

  // --- SORT HANDLER ---
  const handleSort = (key: SortOption) => {
      let direction: 'asc' | 'desc' = 'asc';
      if (sortConfig.key === key && sortConfig.direction === 'asc') {
          direction = 'desc';
      }
      setSortConfig({ key, direction });
  };

  const clearFilters = () => {
    setFilterProject('');
    setFilterMacro('');
    setFilterProcess('');
    setFilterState('');
    setSearchTerm('');
  };

  // --- FILTER & SORT LOGIC ---
  const processedDocs = useMemo(() => {
      let filtered = [...docs];

      if (filterProject) filtered = filtered.filter(d => d.project === filterProject);
      if (filterMacro) filtered = filtered.filter(d => d.macroprocess === filterMacro);
      if (filterProcess) filtered = filtered.filter(d => d.process === filterProcess);
      if (filterState) filtered = filtered.filter(d => d.state === filterState);

      if (searchTerm) {
          const lowerTerm = searchTerm.toLowerCase();
          filtered = filtered.filter(d => 
              (d.project || '').toLowerCase().includes(lowerTerm) ||
              (d.microprocess || '').toLowerCase().includes(lowerTerm) ||
              (d.title || '').toLowerCase().includes(lowerTerm)
          );
      }

      return filtered.sort((a, b) => {
          const modifier = sortConfig.direction === 'asc' ? 1 : -1;
          switch (sortConfig.key) {
              case 'microprocess': return (a.microprocess || '').localeCompare(b.microprocess || '') * modifier;
              case 'state': return ((STATE_CONFIG[a.state]?.progress || 0) - (STATE_CONFIG[b.state]?.progress || 0)) * modifier;
              case 'updatedAt': return (new Date(a.updatedAt).getTime() - new Date(b.updatedAt).getTime()) * modifier;
              default: return 0;
          }
      });
  }, [docs, filterProject, filterMacro, filterProcess, filterState, searchTerm, sortConfig]);

  const SortIcon = ({ column }: { column: SortOption }) => {
      if (sortConfig.key !== column) return <ArrowUpDown size={14} className="text-slate-300 ml-1 opacity-0 group-hover:opacity-100 transition-opacity" />;
      return sortConfig.direction === 'asc' ? <ArrowUp size={14} className="text-indigo-600 ml-1" /> : <ArrowDown size={14} className="text-indigo-600 ml-1" />;
  };

  if (loading) return <div className="p-8 text-center text-slate-500 flex flex-col items-center"><Activity className="animate-spin mb-2" />Cargando lista de trabajo...</div>;

  return (
    <div className="space-y-6 pb-12 animate-fadeIn">
      <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
        <div>
            <h1 className="text-2xl font-bold text-slate-900 flex items-center gap-2">
                <ListTodo className="text-indigo-600" />
                Lista de Trabajo
            </h1>
            <p className="text-slate-500 text-sm">
                {user.role === UserRole.ANALYST ? 'Mis asignaciones pendientes.' : 'Revisiones y asignaciones pendientes.'}
            </p>
        </div>
      </div>

      <div className="bg-white rounded-xl shadow-sm border border-slate-200 overflow-hidden">
            <div className="p-4 border-b border-slate-100 bg-slate-50/50">
                <div className="flex justify-between items-center mb-4">
                    <h2 className="font-bold text-slate-800 flex items-center gap-2 text-sm uppercase tracking-wider">
                        <Filter size={16} className="text-indigo-600" />
                        Filtros de Búsqueda
                    </h2>
                    {(filterProject || filterMacro || filterProcess || filterState || searchTerm) && (
                        <button onClick={clearFilters} className="text-xs text-red-500 hover:text-red-700 font-bold flex items-center gap-1 transition-colors">
                            <X size={14} /> Limpiar Filtros
                        </button>
                    )}
                </div>

                <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-5 gap-3">
                    {/* Filtro Proyecto */}
                    <div className="relative">
                        <FolderTree size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterProject} 
                            onChange={(e) => { setFilterProject(e.target.value); setFilterMacro(''); setFilterProcess(''); }}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white cursor-pointer"
                        >
                            <option value="">PROYECTO</option>
                            {availableProjects.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>

                    {/* Filtro Macroproceso */}
                    <div className="relative">
                        <Layers size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterMacro} 
                            onChange={(e) => { setFilterMacro(e.target.value); setFilterProcess(''); }}
                            disabled={!filterProject && availableMacros.length === 0}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white disabled:bg-slate-100 cursor-pointer"
                        >
                            <option value="">MACROPROCESO</option>
                            {availableMacros.map(m => <option key={m} value={m}>{m}</option>)}
                        </select>
                    </div>

                    {/* Filtro Proceso */}
                    <div className="relative">
                        <Network size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterProcess} 
                            onChange={(e) => setFilterProcess(e.target.value)}
                            disabled={!filterMacro && availableProcesses.length === 0}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white disabled:bg-slate-100 cursor-pointer"
                        >
                            <option value="">PROCESO</option>
                            {availableProcesses.map(p => <option key={p} value={p}>{p}</option>)}
                        </select>
                    </div>

                    {/* Filtro Estado */}
                    <div className="relative">
                        <Activity size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <select 
                            value={filterState} 
                            onChange={(e) => setFilterState(e.target.value)}
                            className="w-full pl-10 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none bg-white cursor-pointer"
                        >
                            <option value="">ESTADO</option>
                            {Object.keys(STATE_CONFIG).filter(k => k !== DocState.APPROVED).map(key => (
                                <option key={key} value={key}>{STATE_CONFIG[key as DocState].label.split('(')[0]}</option>
                            ))}
                        </select>
                    </div>

                    {/* Buscador de texto */}
                    <div className="relative">
                        <Search size={16} className="absolute left-3 top-1/2 -translate-y-1/2 text-slate-400" />
                        <input 
                            type="text" 
                            placeholder="BUSCAR..." 
                            value={searchTerm}
                            onChange={(e) => setSearchTerm(e.target.value)}
                            className="w-full pl-10 pr-8 p-2 border border-slate-300 rounded-lg text-xs font-bold focus:ring-2 focus:ring-indigo-500 outline-none"
                        />
                        {searchTerm && (
                            <button onClick={() => setSearchTerm('')} className="absolute right-2 top-1/2 -translate-y-1/2 text-slate-400 hover:text-slate-600"><X size={14} /></button>
                        )}
                    </div>
                </div>
            </div>

            <div className="overflow-x-auto">
                <table className="w-full text-sm text-left">
                    <thead className="text-[10px] text-slate-400 uppercase font-black tracking-widest bg-slate-50 border-b border-slate-100">
                        <tr>
                            <th className="px-4 py-4">Jerarquía Organizacional</th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('microprocess')}>Microproceso <SortIcon column="microprocess" /></th>
                            <th className="px-4 py-4">Documento / Tipo</th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('state')}>Estado Actual <SortIcon column="state" /></th>
                            <th className="px-4 py-4 cursor-pointer hover:bg-slate-100 group" onClick={() => handleSort('updatedAt')}>Última Actividad <SortIcon column="updatedAt" /></th>
                            <th className="px-4 py-4 text-right">Gestión</th>
                        </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                        {processedDocs.length === 0 ? (
                            <tr>
                                <td colSpan={6} className="p-20 text-center text-slate-400">
                                    <div className="flex flex-col items-center">
                                        <Search size={40} className="mb-2 opacity-20" />
                                        <p className="font-bold">No se encontraron tareas pendientes.</p>
                                        <p className="text-xs mt-1 text-slate-400">Ajuste sus filtros o verifique su bandeja de entrada.</p>
                                    </div>
                                </td>
                            </tr>
                        ) : (
                            processedDocs.map((doc, idx) => (
                                <tr key={`${doc.id}-${idx}`} className={`group hover:bg-slate-50/50 transition-colors ${doc.hasPendingRequest ? 'bg-indigo-50/30' : ''}`}>
                                    <td className="px-4 py-4">
                                        <div className="flex items-center gap-2 mb-1">
                                            <span className="text-[9px] font-black bg-slate-800 text-white px-1.5 py-0.5 rounded tracking-tighter uppercase">{doc.project}</span>
                                            <span className="text-[9px] font-bold text-slate-400 uppercase truncate max-w-[120px]">{doc.macroprocess}</span>
                                        </div>
                                        <div className="text-[10px] text-slate-500 pl-1 border-l border-slate-200 truncate max-w-[180px]">{doc.process}</div>
                                    </td>
                                    <td className="px-4 py-4 font-black text-slate-800 uppercase tracking-tight">
                                        {doc.microprocess || 'General'}
                                    </td>
                                    <td className="px-4 py-4">
                                        <div className="flex items-center gap-2">
